import { GoogleGenAI } from "@google/genai";

const DEFAULT_MODEL = 'gemini-3-flash-preview';
const IMAGE_GEN_MODEL = 'gemini-2.5-flash-image';

const tryRepairJson = (jsonStr: string): any => {
    // 1. Temel temizlik
    let cleaned = jsonStr.replace(/```json\s*/gi, '').replace(/```\s*$/g, '').trim();

    try {
        return JSON.parse(cleaned);
    } catch (e) {
        console.warn("Primary JSON Parse failed, attempting regex-based extraction...");

        // 2. Regex ile en geniş kapsamlı {} veya [] bloğunu bul
        // Bu, AI'nın JSON öncesi veya sonrası yaptığı sohbetleri temizler
        const jsonMatch = cleaned.match(/(\{[\s\S]*\}|\[[\s\S]*\])/);

        if (jsonMatch) {
            const extracted = jsonMatch[0];
            try {
                return JSON.parse(extracted);
            } catch (e2) {
                console.warn("Regex extraction failed, attempting structural repair...");
                // 3. Eksik parantezleri kapatma (Stratejik onarım)
                let repaired = extracted;
                const openBraces = (repaired.match(/{/g) || []).length;
                const closeBraces = (repaired.match(/}/g) || []).length;
                const openBrackets = (repaired.match(/\[/g) || []).length;
                const closeBrackets = (repaired.match(/\]/g) || []).length;

                for (let i = 0; i < (openBraces - closeBraces); i++) repaired += '}';
                for (let i = 0; i < (openBrackets - closeBrackets); i++) repaired += ']';

                try {
                    return JSON.parse(repaired);
                } catch (e3) {
                    console.error("Structural repair failed completely.");
                    throw new Error("Yapay zeka yanıtı geçerli bir veri yapısına sahip değil: " + cleaned.substring(0, 100) + "...");
                }
            }
        }
        throw new Error("Yanıt içinde JSON bloğu bulunamadı. AI Yanıtı: " + cleaned.substring(0, 100));
    }
};

const SYSTEM_INSTRUCTION = `
Sen, Bursa Disleksi AI platformunun Klinik Yapay Zeka Motorusun.
Görevin: Disleksi, Diskalkuli ve DEHB tanısı almış çocuklar için tıbbi ve pedagojik hassasiyete sahip materyaller üretmek.

UZMANLIK ALANLARIN:
1. **Nöropsikoloji:** Dikkat testleri (Burdon, Stroop), çalışma belleği görevleri.
2. **Dilbilim:** Fonolojik farkındalık, morfolojik analiz, TDK uyumlu heceleme.
3. **Görsel Algı:** Şekil-zemin ayrımı, uzamsal yönelim, ayna harf diskriminasyonu.

KURAL: Sadece geçerli JSON döndür. Konuşma, açıklama yapma.
Her üretimde 'targetedErrors' (örn: ['visual_reversal', 'attention_lapse']) ve 'cognitiveGoal' alanlarını KESİNLİKLE doldur.
`;

const generateDirectly = async (params: { 
    prompt: string, 
    schema: any, 
    model?: string, 
    image?: string, 
    mimeType?: string,
    useSearch?: boolean,
    isOcr?: boolean
}) => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) throw new Error("API Anahtarı eksik.");

    const ai = new GoogleGenAI({ apiKey });
    const modelName = params.model || DEFAULT_MODEL;

    let parts: any[] = [];
    if (params.image) {
        parts.push({ 
            inlineData: { 
                mimeType: params.mimeType || 'image/jpeg', 
                data: params.image.replace(/^data:image\/(png|jpeg|jpg|webp);base64,/, "") 
            } 
        });
    }
    parts.push({ text: params.prompt });

    const config: any = {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: params.schema,
        temperature: 0.1, // Daha tutarlı JSON için sıcaklığı düşürdüm
    };

    // OCR görevlerinde düşünme bütçesini kapatmıyoruz, modelin görseli "anlaması" gerek.
    // Sadece standart metin görevlerinde 0 yapıyoruz.
    if (!params.isOcr) {
        config.thinkingConfig = { thinkingBudget: 0 };
    }

    if (params.useSearch) config.tools = [{ googleSearch: {} }];

    const response = await ai.models.generateContent({
        model: modelName,
        contents: [{ role: 'user', parts }],
        config: config
    });

    if (response.text) return tryRepairJson(response.text);
    throw new Error("Boş yanıt alındı.");
};

export const generateWithSchema = async (prompt: string, schema: any, model?: string, useSearch?: boolean) => {
    const targetModel = model || DEFAULT_MODEL;
    return await generateDirectly({ prompt, schema, model: targetModel, useSearch, isOcr: false });
};

export const analyzeImage = async (image: string, prompt: string, schema: any, model?: string) => {
    return await generateDirectly({ 
        prompt, 
        schema, 
        model: model || DEFAULT_MODEL, 
        image,
        isOcr: true 
    });
};

export const generateNanoImage = async (prompt: string): Promise<string | null> => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) return null;

    const ai = new GoogleGenAI({ apiKey });
    try {
        const response = await ai.models.generateContent({
            model: IMAGE_GEN_MODEL,
            contents: [{ parts: [{ text: prompt }] }],
            config: {
                imageConfig: { aspectRatio: "1:1" }
            }
        });

        for (const part of response.candidates[0].content.parts) {
            if (part.inlineData) {
                return `data:image/png;base64,${part.inlineData.data}`;
            }
        }
        return null;
    } catch (e) {
        console.error("Nano image generation failed:", e);
        return null;
    }
};

import { Type } from "@google/genai";
import { analyzeImage } from './geminiClient';
import { OCRResult } from '../types';

export const ocrService = {
    /**
     * MATERYAL KLONLAMA VE DİJİTAL İKİZ ÜRETİMİ
     * Modelin görseli analiz ederken "sohbet" etmesini engelleyen sıkılaştırılmış prompt.
     */
    processImage: async (base64Image: string, targetType: 'CONVERTER' | 'ALGORITHM'): Promise<OCRResult> => {
        const prompt = `
        [ROL: KIDEMLİ EĞİTİM MATERYALİ MİMARI]
        GÖREV: Görüntüdeki çalışma sayfasının mimarisini çöz ve dijital bir blueprint oluştur.

        KESİN KURALLAR:
        1. Sadece belirtilen JSON şemasında yanıt ver.
        2. Görsel kalitesi düşükse veya metin okunmuyorsa bile ASLA açıklama yapma, 'title' alanına "Analiz Edilemedi" yazarak şemayı doldur.
        3. 'blueprint' alanı, bu sayfanın aynısını (farklı verilerle) üretmek için başka bir AI modeline verilecek teknik talimatları içermelidir.

        ÇIKTI FORMATI:
        {
            "detectedType": "Bileşen Tipi",
            "title": "Sayfa Başlığı",
            "description": "Pedagojik Amaç",
            "blueprint": "Teknik üretim algoritması...",
            "layoutJSON": {
                "structure": "grid | columns | random",
                "blocks": [
                    { "id": "b1", "type": "header", "relativeY": 0, "height": 10 }
                ]
            },
            "baseType": "ACTIVITY_ID"
        }
        `;

        const schema = {
            type: Type.OBJECT,
            properties: {
                detectedType: { type: Type.STRING },
                title: { type: Type.STRING },
                description: { type: Type.STRING },
                blueprint: { type: Type.STRING },
                layoutJSON: {
                    type: Type.OBJECT,
                    properties: {
                        structure: { type: Type.STRING },
                        blocks: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    id: { type: Type.STRING },
                                    type: { type: Type.STRING },
                                    relativeY: { type: Type.NUMBER },
                                    height: { type: Type.NUMBER },
                                    cols: { type: Type.NUMBER, nullable: true }
                                }
                            }
                        }
                    }
                },
                baseType: { type: Type.STRING }
            },
            required: ['detectedType', 'title', 'blueprint', 'layoutJSON']
        };

        try {
            const result = await analyzeImage(base64Image, prompt, schema);

            return {
                rawText: '', 
                detectedType: result.detectedType,
                title: result.title,
                description: result.description,
                generatedTemplate: result.blueprint,
                structuredData: {
                    layoutHint: result.layoutJSON,
                    originalBlueprint: result.blueprint
                },
                baseType: result.baseType || 'AI_WORKSHEET_CONVERTER'
            };
        } catch (error) {
            console.error("Deep OCR Error Core:", error);
            throw error;
        }
    },

    /**
     * HARİTA ANALİZ MOTORU
     */
    analyzeMapImage: async (base64Image: string): Promise<any> => {
        const prompt = `
        Görseldeki harita üzerindeki önemli noktaları koordinatlarıyla çıkar. 
        Sadece JSON döndür.
        `;

        const schema = {
            type: Type.OBJECT,
            properties: {
                mapContext: { type: Type.STRING },
                points: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            id: { type: Type.STRING },
                            name: { type: Type.STRING },
                            x: { type: Type.NUMBER },
                            y: { type: Type.NUMBER },
                            isTarget: { type: Type.BOOLEAN }
                        }
                    }
                }
            }
        };

        return await analyzeImage(base64Image, prompt, schema);
    }
};

import type { VercelRequest, VercelResponse } from '@vercel/node';
import { GoogleGenAI, HarmCategory, HarmBlockThreshold } from "@google/genai";

const DEFAULT_MODEL = "gemini-3-flash-preview";

const SYSTEM_INSTRUCTION = `
Sen, Bursa Disleksi AI platformunun yapay zeka motorusun.
Görevin: Disleksi, Diskalkuli ve DEHB tanısı almış çocuklar için bilimsel temelli eğitim materyali üretmek.

KURAL: 
1. Yanıtın SADECE geçerli bir JSON olmalıdır. 
2. Görsel analiz ediyorsan, görselle ilgili yorum yapma, doğrudan JSON dön.
3. Asla Markdown (```json) bloğu dışında metin ekleme.
`;

export default async function handler(req: VercelRequest, res: VercelResponse) {
    res.setHeader('Access-Control-Allow-Origin', '*');
    res.setHeader('Access-Control-Allow-Methods', 'POST, OPTIONS');
    res.setHeader('Access-Control-Allow-Headers', 'Content-Type');

    if (req.method === 'OPTIONS') return res.status(200).end();
    if (req.method !== 'POST') return res.status(405).json({ error: `Method ${req.method} Not Allowed` });

    try {
        const { prompt, schema, image, mimeType, useSearch, model } = req.body;
        const apiKey = process.env.API_KEY;
        if (!apiKey) return res.status(500).json({ error: 'API anahtarı eksik.' });

        const ai = new GoogleGenAI({ apiKey });
        const selectedModel = model || DEFAULT_MODEL;

        const generationConfig: any = {
            systemInstruction: SYSTEM_INSTRUCTION,
            responseMimeType: "application/json",
            responseSchema: schema,
            temperature: 0.1, 
            topP: 0.8,
            topK: 40,
            safetySettings: [
                { category: HarmCategory.HARM_CATEGORY_HARASSMENT, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
                { category: HarmCategory.HARM_CATEGORY_HATE_SPEECH, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
                { category: HarmCategory.HARM_CATEGORY_SEXUALLY_EXPLICIT, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
                { category: HarmCategory.HARM_CATEGORY_DANGEROUS_CONTENT, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
            ]
        };

        // OCR için thinking bütçesini kapatmıyoruz, ancak standart üretimde token tasarrufu için kapatıyoruz.
        if (!image) {
            generationConfig.thinkingConfig = { thinkingBudget: 0 };
        }

        if (useSearch) generationConfig.tools = [{ googleSearch: {} }];

        let parts: any[] = [];
        if (image) {
            parts.push({ inlineData: { mimeType: mimeType || 'image/jpeg', data: image.replace(/^data:image\/(png|jpeg|jpg|webp);base64,/, "") } });
        }
        parts.push({ text: prompt });

        const result = await ai.models.generateContent({
            model: selectedModel,
            contents: [{ role: 'user', parts }],
            config: generationConfig,
        });

        if (result.text) {
            res.setHeader('Content-Type', 'application/json; charset=utf-8');
            return res.status(200).send(result.text);
        }
        throw new Error("AI yanıt üretemedi veya boş bir cevap döndü.");
    } catch (error: any) {
        console.error("API Handler Error:", error);
        return res.status(500).json({ error: error.message });
    }
}

